import socket
import json
import network
from machine import Pin

# Replace with your WiFi SSID and password
ssid = 'your_ssid'
password = 'your_password'

# Initiate Wifi
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect(ssid, password)

while not wlan.isconnected():
    pass  # Wait for connecting to Wifi

print('Wifi connected')

# Create a socket instance
s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)

# Bind the socket to the server's address 
s.bind(('0.0.0.0', 80))  

# Listen to incoming commands
s.listen(5)

# Configure pin 2
pin = Pin(2, Pin.OUT)

# Define WebSocket handshake response
handshake = """HTTP/1.1 101 Switching Protocols
Upgrade: websocket
Connection: Upgrade
Sec-WebSocket-Accept: {}
\r\n\r\n"""

# Main loop
while True:
    print('Listening for new client...')
    client_socket, address = s.accept()

    print('New client connected!')
    client_socket.settimeout(15.0)

    # Perform the WebSocket handshake
    request = client_socket.recv(600)
    if b'Sec-WebSocket-Key' in request:
        ws_key = request.split(b'Sec-WebSocket-Key')[1].split(b'\r\n')[0].strip()
        client_socket.send(str(handshake.format(ws_key)).encode())
        
    else:
        print('No WebSocket key in client handshake, closing connection.')
        client_socket.close()
        continue

    while True:
        try:
            # Read and process incoming message
            msg = client_socket.read()
            if not msg:
                break

            # Decode message
            msg = msg.decode('utf-8')

            # Try to parse JSON
            try:
                msg = json.loads(msg)

                if 'action' in msg and msg['action'] == 'turn_on':
                    pin.on()

                elif 'action' in msg and msg['action'] == 'turn_off':
                    pin.off()

            except json.JSONDecodeError:
                print('Failed to decode incoming message.')

        except OSError as e:
            print('OS exception:', e.args[0])
            break

    print('Closing client connection...')
    client_socket.close()